    const handleToggleAvailability = async (item: MenuItem) => {
        const newStatus = !item.isAvailable;
        setMenuItems(prev => prev.map(i => i.id === item.id ? { ...i, isAvailable: newStatus } : i));

        try {
            await updateMockAvailability(item.id, newStatus);
        } catch (error) {
            console.error("Toggle failed:", error);
            setMenuItems(prev => prev.map(i => i.id === item.id ? { ...i, isAvailable: !newStatus } : i));
        }
    };

    if (loading) return <p className="text-gray-300 text-center py-10">Loading screens...</p>;

    return (
        <div className="mt-8">
            <div className="flex justify-between items-center mb-6">
                <h1 className="text-4xl font-bold text-gray-200">Screens Menu 🎬</h1>
            </div>

