                                placeholder="e.g., SCREEN 1, SCREEN 2" 
                            />
                            <p className="text-xs text-gray-500 -mt-3 mb-2">Enter available slots separated by commas.</p>

                             <div>
                                <label className="block text-gray-300 font-semibold mb-2">Screen Image</label>
                                <div className="flex items-center gap-4">
                                    <div className="w-24 h-24 flex-shrink-0 bg-gray-900 rounded-lg flex items-center justify-center overflow-hidden border border-gray-600">
                                        {isProcessingImage ? (
