                        onClick={onRefresh} 
                        disabled={isRefreshing}
                        className={`group flex items-center gap-2 px-3 py-1.5 rounded-full bg-indigo-600 hover:bg-indigo-500 text-white text-xs font-black uppercase tracking-widest transition-all ${isRefreshing ? 'opacity-50 cursor-not-allowed' : ''}`}
                    >
