  switch (status) {
    case OrderStatus.PENDING:
      return { text: 'Preparing', icon: '⏳', className: 'bg-yellow-500/20 text-yellow-300 border-yellow-400/30' };
    case OrderStatus.PREPARED:
      return { text: 'Ready', icon: '✅', className: 'bg-blue-500/20 text-blue-300 border-blue-400/30' };
    case OrderStatus.PARTIALLY_DELIVERED:
      return { text: 'Partial', icon: '📦', className: 'bg-orange-500/20 text-orange-300 border-orange-400/30' };
    case OrderStatus.COLLECTED:
    case OrderStatus.COMPLETED:
      return { text: 'Completed', icon: '🏁', className: 'bg-green-500/20 text-green-300 border-green-400/30' };
    case OrderStatus.CANCELLED:
      return { text: 'Cancelled', icon: '❌', className: 'bg-red-500/20 text-red-300 border-red-400/30' };
    default:
      return { text: status, icon: '❓', className: 'bg-gray-500/20 text-gray-300 border-gray-400/30' };
  }
};

