                                                <button onClick={() => handleStatusUpdate(order.id, OrderStatus.PREPARED)} className="bg-blue-600 text-white font-bold py-1 px-3 rounded text-xs hover:bg-blue-500">Ready</button>
                                            }
                                        </div>
