                                        ? (isChecking ? 'Verifying...' : (isAvailable === false ? 'Already Booked' : (selectedSlot ? 'Add screen to Cart' : 'Select a Slot'))) 
                                        : (item.isAvailable ? 'Add to Cart' : 'Out of Stock')
                                    }
                                </Button>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

