export const verifyQrCode = async (token: string): Promise<Order> => { 
    const { data: order, error } = await supabase.from('orders').select('*, order_items(*)').eq('qr_token', token.trim()).maybeSingle();
    if (error) throw new Error(error.message);
    if (!order) throw new Error("Invalid QR"); 
    return mapOrder(order);
};
export const updatePartialDelivery = async (orderId: string, itemIds: string[], staffId: string): Promise<Order> => {
    await supabase.from('order_items').update({ is_delivered: true }).eq('order_id', orderId).in('menu_item_id', itemIds);
    const { data: updatedOrder, error: orderErr } = await supabase.from('orders').update({ status: OrderStatusEnum.COLLECTED, collected_at: new Date().toISOString() }).eq('id', orderId).select('*, order_items(*)').single();
    if (orderErr) throw orderErr;
    return mapOrder(updatedOrder);
};
export const verifyQrCodeAndCollectOrder = async (token: string, staffId: string): Promise<Order> => { 
    const order = await verifyQrCode(token); 
    return await updatePartialDelivery(order.id, order.items.map(i => i.id), staffId);
