        const style: React.CSSProperties = {
            left: `${Math.random() * 100}%`,
            top: `${Math.random() * 100}%`,
            fontSize: `${Math.random() * 1.5 + 2}rem`,
            animation: `float ${Math.random() * 10 + 10}s ease-in-out ${Math.random() * 5}s infinite`,
            filter: 'drop-shadow(0 0 15px rgba(0, 242, 255, 0.6))',
            opacity: 0.4
        };
        return (
            <span key={i} className="absolute" style={style}>
                {foods[i % foods.length]}
            </span>
        );
    });
    return <div className="absolute inset-0 z-10 overflow-hidden pointer-events-none">{items}</div>;
};

